import { Job } from 'bull';
import { Redis } from 'ioredis';
import { Inject, Service } from 'typedi';
import winston from 'winston';

import { Logger } from '@Decorators/Logger';

import Queueable from '@Libs/queue/Queueable';

import { NotificationJobInput } from '@Jobs/types/NotificationJobInput';

import { INotificationService } from '@Services/integration/INotificationService';

@Service()
export class NotificationJob extends Queueable<NotificationJobInput> {
  constructor(
    @Logger(module) readonly logger: winston.Logger,
    @Inject('cache') readonly cache: Redis,
    private readonly notificationService: INotificationService,
  ) {
    super(logger, cache);
  }

  public queueName(): string {
    return 'NotificationJob';
  }

  public async processHandler(job: Job<NotificationJobInput>) {
    this.logger.warn(`NotificationJob:: process data: `, job.data);
    const { notifications } = job.data;
    if (!notifications?.length) {
      this.logger.warn('NotificationJob:: No notifications to send');
      return;
    }

    try {
      await this.notificationService.batchSendNotification({ notifications });
    } catch (error) {
      this.logger.error('NotificationJob:: Failed to call notification service', {
        error,
        totalNotifications: notifications.length,
      });
      throw error;
    }
  }
}

