import { Job } from 'bull';
import { Redis } from 'ioredis';
import { Inject, Service } from 'typedi';
import winston from 'winston';

import { Logger } from '@Decorators/Logger';

import { createClient } from '@Libs/axios';
import Queueable from '@Libs/queue/Queueable';

import { CallExternalJobInput } from '@Jobs/types/CallExternalJobInput';

@Service()
export class CallExternalJob extends Queueable<CallExternalJobInput> {
  constructor(@Logger(module) readonly logger: winston.Logger, @Inject('cache') readonly cache: Redis) {
    super(logger, cache);
  }

  public queueName(): string {
    return 'CallExternalJob';
  }

  public async processHandler(job: Job<CallExternalJobInput>) {
    this.logger.warn(`CallExternalJob:: process data: `, job.data);
    const { serviceName, webhookUrl, webhookConfig, apiPath, payload } = job.data;
    try {
      const client = createClient(webhookUrl, { 'x-api-key': webhookConfig, Accept: 'application/json' }, serviceName);

      await client.post(apiPath, payload);
    } catch (error) {
      this.logger.error('CallExternalJob:: Failed to push webhook', {
        serviceName,
        webhookUrl,
        apiPath,
        error,
      });
      throw error;
    }
  }
}

