import dayjs from 'dayjs';
import { NotFoundError } from 'routing-controllers';
import { Service } from 'typedi';
import winston from 'winston';

import { Logger } from '@Decorators/Logger';

import { removeAccents } from '@Libs/utils/string';
import { env } from '@Libs/env';

import { NotificationChannel, NotificationSendType, NotificationType, RecipientRefType } from '@Enums/Notification';
import { HotelWebhookEvent } from '@Enums/hotels/Hotel';

import { NotificationJob } from '@Jobs/NotificationJob';

import { BusinessLogicError } from '@Errors/BusinessLogicError';
import { ErrorCode } from '@Errors/ErrorCode';

import { RequestQuote } from '@Entities/RequestQuote';
import { ServiceRegistry } from '@Entities/ServiceRegistry';

import { Identity } from '@DBCommon/Identity';

import { RequestQuoteRepository } from '@Repositories/RequestQuoteRepository';

import { CreateRequestQuoteInput, RequestQuoteQueryParamInput } from '@Services/types/RequestQuoteInput';
import { UpdateRequestQuoteInput } from '@Services/types/hotel/RequestQuoteInput';
import { ServiceRegistryService } from '@Services/ServiceRegistryService';
import { INotificationService } from '@Services/integration/INotificationService';

@Service()
export class RequestQuoteService {
  constructor(
    @Logger(module) private readonly logger: winston.Logger,

    private readonly requestQuoteRepo: RequestQuoteRepository,
    private readonly registryService: ServiceRegistryService,
    private readonly iNotificationService: INotificationService,
    private readonly notificationJob: NotificationJob,
  ) {}
  private async newRequestQuote(requestQuote: RequestQuote, reg?: ServiceRegistry) {
    const notifications = [...env.integration.notification.mailToOPS].filter(Boolean).map(item => ({
      recipient: item,
      content: JSON.stringify({
        ...requestQuote,
        checkInDate: dayjs(requestQuote.startDate).format('DD/MM/YYYY'),
        checkOutDate: dayjs(requestQuote.endDate).format('DD/MM/YYYY'),
        numberOfNights: dayjs(requestQuote.endDate).diff(dayjs(requestQuote.startDate), 'day'),
      }),
      subject: `Yêu cầu báo giá - Mã ${requestQuote.code} - ${requestQuote.request} - [${dayjs(
        requestQuote.startDate,
      ).format('DD')} - ${dayjs(requestQuote.endDate).format('DD/MM/YYYY')}]`,
      type: NotificationType.YCG_NEW,
      recipientRefType: RecipientRefType.AGENCY,
      recipientRefId: String(reg.id),
      channel: NotificationChannel.EMAIL,
      sendType: NotificationSendType.INSTANT,
      isReschedule: false,
      isActive: true,
    }));

    if (notifications.length > 0) {
      await this.notificationJob.dispatch({ notifications });
    }
  }
  private generateRequestQuoteCode(id: number): string {
    // Generate code format: RQ + id (minimum 6 digits)
    const paddedId = id.toString().padStart(6, '0');
    return `RQ${paddedId}`;
  }

  async create(payload: CreateRequestQuoteInput, reg?: ServiceRegistry) {
    if (
      dayjs(payload.startDate).isAfter(dayjs(payload.endDate)) ||
      dayjs(payload.startDate).isSame(dayjs(payload.endDate)) ||
      dayjs(payload.startDate).isBefore(dayjs(), 'day')
    ) {
      throw new NotFoundError(ErrorCode.INVALID_DATE_RANGE);
    }
    const entity = new RequestQuote();
    Object.assign(entity, payload);
    const nextId = await this.requestQuoteRepo.getNextId();
    entity.code = this.generateRequestQuoteCode(nextId);
    entity.createdBy = payload.username;
    entity.agencyCode = removeAccents(payload.agencyCode?.toLowerCase() || '');
    if (!reg) {
      reg = await this.registryService.default();
    }
    entity.serviceRegistry = reg;
    const rs = await this.requestQuoteRepo.insert(entity);
    this.newRequestQuote(rs, reg);
    if (reg)
      if (!reg.webhookUrl || !reg.webhookConfig) {
        this.logger.warn('RequestQuoteService::create:: Webhook URL or Config is missing in Service Registry');
      } else {
        reg.push('/webhook/hotel/request-quotes', rs).catch(err => {
          this.logger.error('RequestQuoteService::create:: Error pushing to webhook:', err);
        });
      }
    return rs;
  }

  async findAll(query: RequestQuoteQueryParamInput, reg?: ServiceRegistry) {
    query.serviceRegistry = reg;
    return this.requestQuoteRepo.findAll(query);
  }

  async findById(id: number, reg?: ServiceRegistry) {
    // const entity = await this.requestQuoteRepo.findOne({
    //   where: { id, serviceRegistry: { id: reg.id } },
    //   relations: ['serviceRegistry'],
    // });
    const entity = await this.requestQuoteRepo.findById(id);
    if (!entity) throw new NotFoundError(ErrorCode.REQUEST_QUOTE_NOT_FOUND);
    return entity;
  }

  async update(id: number, payload: UpdateRequestQuoteInput, identity: Identity) {
    const entity = await this.requestQuoteRepo.findById(id, { relations: ['serviceRegistry'] });
    if (!entity) throw new NotFoundError(ErrorCode.REQUEST_QUOTE_NOT_FOUND);

    if (payload.response && entity.response) throw new BusinessLogicError(ErrorCode.REQUEST_QUOTE_ALREADY_RESPONDED);
    const result = await this.requestQuoteRepo.partialUpdate(id, payload, identity.username);

    if (!entity.serviceRegistry.webhookUrl || !entity.serviceRegistry.webhookConfig) {
      this.logger.warn('RequestQuoteService::update:: Webhook URL or Config is missing in Service Registry');
    } else {
      Object.assign(entity, payload);
      entity.serviceRegistry
        .push('/webhook/hotel', { event: HotelWebhookEvent.HOTEL_REQUEST_QUOTE, payload: entity })
        .catch(err => {
          this.logger.error('RequestQuoteService::update:: Error pushing to webhook:', err);
        });
    }
    if (result.affected && result.affected > 0) return true;
    return false;
  }
}
